        <div className="editor-palette bg-secondary rounded-lg border border-color p-4">
          <h4 className="text-sm font-semibold mb-4 text-muted uppercase">Available Steps</h4>
          <div className="flex-col gap-3">
            {Object.entries(stepTypes).map(([type, template]) => {
              const Icon = template.icon;
              return (
                <div key={type} className="palette-item">
                  <div className={`p-2 rounded-md bg-opacity-20 ${template.color} ${template.bg}`}>
                    <Icon size={18} />
                  </div>
                  <span className="font-medium text-sm">{template.label}</span>
                </div>
              );
            })}
          </div>
        </div>

        {/* Main Canvas - Drag & Drop */}
        <div className="editor-canvas flex-1 p-6 bg-tertiary rounded-lg border border-color overflow-y-auto">
          <DragDropContext onDragEnd={handleDragEnd}>
            <Droppable droppableId="workflow-steps">
              {(provided) => (
                <div 
                  className="steps-container"
                  {...provided.droppableProps}
                  ref={provided.innerRef}
                >
                  {steps.map((step, index) => {
                    const Template = stepTypes[step.type];
                    const Icon = Template.icon;
                    return (
                      <Draggable key={step.id} draggableId={step.id} index={index}>
                        {(provided, snapshot) => (
                          <div
                            ref={provided.innerRef}
                            {...provided.draggableProps}
                            className={`workflow-step-card ${snapshot.isDragging ? 'dragging' : ''}`}
                          >
                            <div className="step-drag-handle" {...provided.dragHandleProps}>
                              <GripVertical size={20} className="text-muted" />
                            </div>

                            <div className="step-content">
                              <div className="flex items-center gap-3 mb-2">
                                <div className={`p-1.5 rounded-md text-white ${Template.bg}`}>
                                  <Icon size={16} />
                                </div>
                                <span className="text-xs font-semibold uppercase tracking-wider text-muted">
                                  {Template.label}
                                </span>
                              </div>
                              <h4 className="font-semibold text-primary-text">{step.title}</h4>
                              <p className="text-sm text-muted mt-1">{step.config}</p>
                            </div>

                            <div className="step-actions">
                              <Button 
                                variant="secondary" 
                                size="sm" 
                                onClick={() => openRuleEditor(step.id)}
                              >
                                Edit Rules
                              </Button>
                              <button 
                                className="icon-btn text-muted hover-text-error border-0 bg-transparent p-2 cursor-pointer transition-colors"
                                onClick={() => removeStep(step.id)}
                              >
                                <X size={18} />
                              </button>
                            </div>

                            {/* Visual connector line (hidden on last item) */}
                            {index < steps.length - 1 && (
                              <div className="step-connector"></div>
                            )}
                          </div>
                        )}
                      </Draggable>
                    )
                  })}
                  {provided.placeholder}

                  <div className="add-step-btn-container mt-8 flex justify-center">
                    <Button variant="ghost" className="border border-dashed border-color text-muted hover-border-primary">
                      <Plus size={20} /> Add Next Step
                    </Button>
                  </div>
                </div>
              )}
            </Droppable>
          </DragDropContext>
        </div>
      </div>

      {/* Rule Editor Modal */}
      <Modal 
        isOpen={isRuleModalOpen} 
        onClose={() => setIsRuleModalOpen(false)}
        title="Edit Step Rules"
        footer={
          <>
            <Button variant="ghost" onClick={() => setIsRuleModalOpen(false)}>Cancel</Button>
            <Button variant="primary" onClick={() => setIsRuleModalOpen(false)}>Save Rules</Button>
          </>
        }
      >
        <div className="flex-col gap-4">
          <p className="text-sm text-muted border-b border-color pb-4">
            Configure conditions and priority for this step across the workflow.
          </p>

          <div className="bg-tertiary p-4 rounded-md border border-color">
            <h5 className="text-sm font-semibold mb-3">Execution Condition</h5>
            <div className="flex items-center gap-3">
              <select className="form-select w-1/3">
                <option>If Previous Status</option>
                <option>If Field Equals</option>
                <option>Always Run</option>
              </select>
              <select className="form-select w-1/3">
                <option>Equals</option>
                <option>Not Equals</option>
              </select>
              <Input className="w-1/3" placeholder="Value (e.g. Success)" />
            </div>
          </div>

          <div className="bg-tertiary p-4 rounded-md border border-color mt-2">
            <h5 className="text-sm font-semibold mb-3">Priority Level</h5>
            <div className="flex gap-4">
              <label className="flex items-center gap-2 cursor-pointer">
                <input type="radio" name="priority" value="high" /> High
              </label>
              <label className="flex items-center gap-2 cursor-pointer">
                <input type="radio" name="priority" value="normal" defaultChecked /> Normal
              </label>
              <label className="flex items-center gap-2 cursor-pointer">
                <input type="radio" name="priority" value="low" /> Low
              </label>
            </div>
          </div>

        </div>
      </Modal>
    </div>
  );
}

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';
import { Search, Filter, Plus, Play, Edit2, Trash2 } from 'lucide-react';
import { Button } from '../../components/ui/Button';
import { Input } from '../../components/ui/Input';
import { Badge } from '../../components/ui/Badge';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '../../components/ui/Table';

const mockWorkflows = [
  { id: 'WF-001', name: 'Customer Onboarding', status: 'active', executions: 1250, lastRun: '10 mins ago' },
  { id: 'WF-002', name: 'Invoice Processing', status: 'draft', executions: 0, lastRun: '-' },
  { id: 'WF-003', name: 'Lead Scoring', status: 'active', executions: 840, lastRun: '1 hour ago' },
  { id: 'WF-004', name: 'Daily DB Backup', status: 'paused', executions: 45, lastRun: '1 day ago' },
  { id: 'WF-005', name: 'Support Ticket Router', status: 'active', executions: 342, lastRun: '5 mins ago' },
];

export function WorkflowList() {
  const [searchTerm, setSearchTerm] = useState('');
  const navigate = useNavigate();

  const filteredWorkflows = mockWorkflows.filter(wf => 
    wf.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="flex-col gap-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-h2">Workflows</h2>
          <p className="text-muted mt-1">Manage and monitor all your automated workflows.</p>
        </div>
        <Button icon={<Plus size={18} />} onClick={() => navigate('/user/editor')}>
          New Workflow
        </Button>
      </div>

      <div className="flex gap-4 items-center">
        <div className="flex-1 max-w-md">
          <Input 
            icon={Search} 
            placeholder="Search workflows..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <Button variant="secondary" icon={<Filter size={18} />}>Filters</Button>
      </div>

      <motion.div 
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        className="mt-4"
      >
        <Table>
          <TableHeader>
            <tr>
              <TableHead>Name</TableHead>
              <TableHead>Status</TableHead>
              <TableHead>Total Executions</TableHead>
              <TableHead>Last Run</TableHead>
              <TableHead className="text-right">Actions</TableHead>
            </tr>
          </TableHeader>
          <TableBody>
            {filteredWorkflows.map((wf) => (
              <TableRow key={wf.id} className="hover:bg-hover">
                <TableCell>
                  <div>
                    <p className="font-semibold text-primary-text">{wf.name}</p>
                    <p className="text-xs text-muted mt-1">{wf.id}</p>
                  </div>
                </TableCell>
                <TableCell>
                  <Badge variant={wf.status === 'active' ? 'success' : wf.status === 'paused' ? 'warning' : 'neutral'}>
                    {wf.status.charAt(0).toUpperCase() + wf.status.slice(1)}
                  </Badge>
                </TableCell>
                <TableCell className="font-medium">{wf.executions.toLocaleString()}</TableCell>
                <TableCell className="text-muted text-sm">{wf.lastRun}</TableCell>
                <TableCell>
                  <div className="flex justify-end gap-2">
                    <Button variant="ghost" size="sm" icon={<Play size={16} />} aria-label="Run" onClick={() => navigate('/user/execution')} />
                    <Button variant="ghost" size="sm" icon={<Edit2 size={16} />} aria-label="Edit" onClick={() => navigate('/user/editor')} />
                    <Button variant="ghost" size="sm" icon={<Trash2 size={16} className="text-error" />} aria-label="Delete" />
                  </div>
                </TableCell>
              </TableRow>
            ))}
            {filteredWorkflows.length === 0 && (
              <TableRow>
                <TableCell colSpan={5} className="text-center py-8 text-muted">
                  No workflows found matching "{searchTerm}"
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </motion.div>
    </div>
  );
}
